  else if @invCode = 'HD1' select @$mTable = 'm21$'+ convert(char(6), (select ngay_ct from c21$000000 where stt_rec = @invID), 112), @$eTable = 'hddt00$'+ convert(char(6), (select ngay_ct from c21$000000 where stt_rec = @invID), 112)
  else if @invCode = 'HD2' select @$mTable = 'm22$'+ convert(char(6), (select ngay_ct from c22$000000 where stt_rec = @invID), 112), @$eTable = 'hddt00$'+ convert(char(6), (select ngay_ct from c22$000000 where stt_rec = @invID), 112)
  else if @invCode = 'HD7' select @$mTable = 'hdtt', @$eTable = 'hddt00$'+ convert(char(6), (select ngay_ct from hdtt where stt_rec = @invID), 112)
  else if @invCode = 'PXC' select @$mTable = 'm86$'+ convert(char(6), (select ngay_ct from c86$000000 where stt_rec = @invID), 112), @$eTable = 'hddt00$'+ convert(char(6), (select ngay_ct from c86$000000 where stt_rec = @invID), 112)
  else if @invCode = 'PXD' select @$mTable = 'm26$000000', @$eTable = 'hddt00$'+ convert(char(6), (select ngay_ct from m26$000000 where stt_rec = @invID), 112)

